opr__breakdown_canceled_screen__text = TextObject(bs_BA="Online poziv zbog kvara je prekinut.\nPoziv se završava.", cs_CZ="Havarijní volání online bylo přerušeno.\nVolání se ukončí.", da_DK="Onlinevejhjælpsopkald blev afbrudt.\nOpkald afsluttes.", de_DE="Der Online-Pannenruf wurde abgebrochen.\nDer Anruf wird beendet.", el_GR="Η online κλήση για βλάβη διακόπηκε.\nΗ κλήση θα τερματιστεί.", en_GB="Online roadside assistance has been cancelled.\nEnding call.", es_ES="La llamada de asistencia online se ha cancelado.\nFinalizando la llamada.", fi_FI="Online-tiepalvelupuhelu on katkennut.\nPuhelu päättyy.", fr_FR="L'appel du service de dépannage en ligne a été annulé.\nFin de l'appel.", hr_HR="Online poziv za pomoć na cesti je prekinut.\nPoziv se završava.", hu_HU="Az online műszaki segélyhívás megszakadt.\nA hívás befejeződik.", it_IT="La chiamata soccorso stradale online è stata interrotta.\nLa chiamata viene terminata.", nl_NL="De online pechoproep is afgebroken.\nDe oproep wordt beëindigd.", no_NO="Online veitjenesten ble avbrutt.\nAvslutter anropet.", pl_PL="Wezwanie pomocy online zostało anulowane.\nPołączenie zostanie zakończone.", pt_PT="A chamada de assistência online foi interrompida.\nA chamada será terminada.", ro_RO="Apelul de pană online a fost întrerupt.\nApelul se încheie.", ru_RU="Онлайн-вызов при аварии прерван.\nКонец вызова.", sk_SK="Online volanie pri poruche sa prerušilo.\nHovor sa ukončí.", sl_SI="Spletni klic ob okvari je bil prekinjen.\nKlic se bo zaključil.", sr_RS="Onlajn poziv u slučaju kvara je prekinut.\nPoziv se završava.", sv_SE="Servicesamtalet online avbröts.\nSamtalet avslutas.", tr_TR="Çevrimiçi arıza çağrısı iptal edildi.\nÇağrı sonlandırılıyor.", uk_UA="Аварійний виклик онлайн перервано.\nВиклик завершується.")
opr__breakdown_collecting_and_sending_data_screen__no_reception__text = TextObject(bs_BA="Podaci se prikupljaju i prenose. Loš prijem mobilne mreže.\nVeza se eventualno neće moći uspostaviti. Sačekajte...", cs_CZ="Data jsou shromažďována a přenášena. Špatný příjem\nmobilního telefonu. Spojení nemusí být navázáno.\nPočkejte prosím…", da_DK="Data indsamles og overføres. Dårlig mobilnetdækning.\nForbindelse kan muligvis ikke oprettes. Vent...", de_DE="Die Daten werden gesammelt und übertragen.\nSchlechter Mobilfunkempfang. Die Verbindung kann\nmöglicherweise nicht aufgebaut werden.\nBitte warten...", el_GR="Γίνεται συλλογή και μετάδοση των δεδομένων. Κακή λήψη\nκινητής τηλεφωνίας. Η σύνδεση ενδέχεται να μην μπορεί να\nδημιουργηθεί. Παρακαλώ περιμένετε...", en_GB="The data will be collected and transmitted. Poor mobile\nnetwork reception. Possibly unable to establish a connection.\nPlease wait…", es_ES="Recopilando y enviando datos. Hay poca cobertura. Es posible\nque no se pueda establecer la conexión. Por favor, espere...", fi_FI="Tietoja kerätään ja siirretään. Huono\nmatkapuhelinvastaanotto. Yhteyttä ei ehkä voi muodostaa.\nOdota...", fr_FR="Collecte et transmission des données en cours. Mauvaise\ncouverture du réseau de téléphonie mobile. La connexion\nrisque de ne pas pouvoir être établie. Veuillez patienter...", hr_HR="Podaci se prikupljaju i šalju. Loš mobilni prijem. Veza se\nvjerojatno neće moći uspostaviti. Čekajte...", hu_HU="Az adatok összegyűjtése és továbbítása történik. Rossz\nmobiltelefon-vétel. Előfordulhat, hogy a kapcsolat nem jön\nlétre. Kérünk, várj...", it_IT="I dati vengono raccolti e trasmessi. Scarsa ricezione della\ntelefonia mobile. Potrebbe risultare impossibile stabilire il\ncollegamento. Attendere prego...", nl_NL="De gegevens worden verzameld en doorgestuurd. Slechte\nmobiele ontvangst. De verbinding wordt mogelijk niet tot\nstand gebracht. Even geduld...", no_NO="Samler inn og overfører data. Dårlig mobildekning. Det er\nikke sikkert forbindelsen kan opprettes. Vent litt...", pl_PL="Dane są gromadzone i przesyłane. Słaby zasięg sieci\nkomórkowej. Połączenie może nie zostać nawiązane.\nProszę czekać...", pt_PT="Os dados serão recolhidos e transferidos. Má receção móvel.\nTalvez não seja possível estabelecer a ligação.\nPor favor, aguardar...", ro_RO="Se colectează şi transmit datele. Calitate slabă a recepţiei\npentru telefonia mobilă. Este posibil să nu se poată realiza\nconexiunea. Vă rugăm aşteptaţi...", ru_RU="Данные собираются и передаются. Плохой прием сети\nмобильной связи. Возможно, соединение не будет\nустановлено. Пожалуйста, ждите...", sk_SK="Údaje sa zbierajú a odošlú. Slabý príjem mobilného telefónu.\nSpojenie sa nemusí nadviazať. Čakajte, prosím...", sl_SI="Zbiranje in prenos podatkov. Slab mobilni sprejem. Povezave\nmorda ni mogoče vzpostaviti. Prosimo, počakajte ...", sr_RS="Podaci se sakupljaju i prenose. Loš prijem mreže mobilne\ntelefonije. Veza eventualno neće moći da se uspostavi.\nMolimo sačekajte...", sv_SE="Data samlas in och överförs. Dålig mottagning. Anslutningen\nkan eventuellt inte upprättas. Vänligen vänta...", tr_TR="Veriler toplanıyor ve aktarılıyor. Mobil şebeke çekimi kötü.\nBağlantı muhtemelen kurulamayabilir. Lütfen bekleyin...", uk_UA="Дані збираються і передаються. Погане приймання мережі\nмобільного зв'язку. Можливо, з'єднання не буде\nвстановлено. Зачекайте...")
opr__breakdown_collecting_and_sending_data_screen__text = TextObject(bs_BA="Podaci se prikupljaju i prenose. Sačekajte...", cs_CZ="Data jsou shromažďována a přenášena. Počkejte prosím…", da_DK="Data indsamles og overføres. Vent...", de_DE="Die Daten werden gesammelt und übertragen. Bitte warten...", el_GR="Γίνεται συλλογή και μετάδοση των δεδομένων.\nΠαρακαλώ περιμένετε...", en_GB="Data will be collected and transmitted. Please wait…", es_ES="Recopilando y enviando datos. Por favor, espere...", fi_FI="Tietoja kerätään ja siirretään. Odota...", fr_FR="Collecte et transmission des données en cours.\nVeuillez patienter...", hr_HR="Podaci se prikupljaju i prenose. Čekajte...", hu_HU="Az adatok összegyűjtése és továbbítása történik.\nKérünk, várj...", it_IT="I dati vengono raccolti e trasmessi. Attendere prego...", nl_NL="De gegevens worden verzameld en verzonden. Even geduld...", no_NO="Samler inn og overfører data. Vent litt...", pl_PL="Trwa gromadzenie i przesyłanie danych. Proszę czekać...", pt_PT="Os dados serão recolhidos e transferidos.\nPor favor, aguardar...", ro_RO="Se colectează şi transferă datele. Aşteptaţi...", ru_RU="Данные собираются и передаются. Пожалуйста, ждите...", sk_SK="Údaje sa zhromažďujú a prenášajú. Čakajte, prosím...", sl_SI="Zbiranje in prenos podatkov.Prosimo, počakajte ...", sr_RS="Podaci se sakupljaju i prenose. Molimo sačekajte...", sv_SE="Data samlas in och överförs. Vänligen vänta...", tr_TR="Veriler toplanıyor ve aktarılıyor. Lütfen bekleyin...", uk_UA="Дані збираються і передаються. Зачекайте...")
opr__breakdown_connected_screen__no_reception__text = TextObject(bs_BA="Veza sa servisnom centralom je uspostavljena.\nLoš prijem mobilne mreže.\nVeza se eventualno može prekinuti.\nVIN: %1\n\nVaša pozicija:\n%2", cs_CZ="Spojení se servisní centrálou bylo vytvořeno.\nŠpatný příjem mobilního signálu.\nSpojení může být přerušené.\nVIN: %1\n\nVaše poloha:\n%2", da_DK="Der er oprettet forbindelse til servicecentralen.\nDårlig mobilnetdækning.\nForbindelse kan muligvis blive afbrudt.\nStelnummer: %1\n\nDin position:\n%2", de_DE="Die Verbindung zur Servicezentrale ist aufgebaut.\nSchlechter Mobilfunkempfang.\nDie Verbindung kann möglicherweise unterbrochen werden.\nVIN: %1\n\nDeine Position:\n%2", el_GR="Δημιουργήθηκε η σύνδεση με το κέντρο εξυπηρέτησης.\nΚακή λήψη σήματος κινητής τηλεφωνίας.\nΕνδέχεται να διακοπεί η σύνδεση.\nVIN: %1\n\nΗ τρέχουσα θέση σας:\n%2", en_GB="Connection to service centre established.\nPoor mobile network reception.\nThe connection may be interrupted.\nVIN: %1\n\nYour position:\n%2", es_ES="Conexión con la central de Servicio establecida.\nHay poca cobertura.\nLa conexión podría cortarse.\nVIN: %1\n\nSu posición:\n%2", fi_FI="Yhteys palvelukeskukseen on muodostettu.\nHuono matkapuhelinvastaanotto.\nYhteys saattaa katketa.\nVIN: %1\n\nSijaintipaikkasi:\n%2", fr_FR="La connexion au centre d'appels est établie.\nMauvaise couverture du réseau de téléphonie mobile.\nLa connexion risque d'être interrompue.\nVIN: %1\n\nVotre position:\n%2", hr_HR="Veza sa servisnom centralom je uspostavljena.\nLoš prijem mobilne mreže.\nVeza će se možda prekinuti.\nVIN: %1\n\nVaša pozicija:\n%2", hu_HU="Az összeköttetés a szolgáltató központtal létrejött.\nRossz mobiltelefon-vétel.\nA kapcsolat megszakadhat.\nVIN: %1\n\nHelyed:\n%2", it_IT="Stabilito collegamento al centro servizi.\nScarsa ricezione della telefonia mobile.\nIl collegamento potrebbe interrompersi.\nVIN: %1\n\nPosizione attuale:\n%2", nl_NL="Verbinding met de Servicecentrale is opgebouwd.\nSlechte mobiele ontvangst.\nDe verbinding kan mogelijk worden onderbroken.\nVIN: %1\n\nJouw positie:\n%2", no_NO="Det er opprettet forbindelse med kundeservice.\nDårlig mobildekning.\nForbindelsen kan bli brutt.\nVIN: %1\n\nDin posisjon:\n%2", pl_PL="Połączenie z centralą serwisową jest nawiązane.\nSłaby zasięg telefonii komórkowej.\nMoże dojść do przerwania połączenia.\nNumer VIN: %1\n\nTwoja pozycja:\n%2", pt_PT="A ligação ao Callcenter está estabelecida.\nDeficiente receção móvel.\nÉ possível que a ligação seja interrompida.\nVIN: %1\n\nA tua posição:\n%2", ro_RO="Conexiunea la centrala de service este realizată.\nCalitate slabă a semnalului de telefonie mobilă.\nEste posibil să se întrerupă conexiunea.\nVIN: %1\n\nPoziţia dumneavoastră:\n%2", ru_RU="Соединение с сервисным колл-центром установлено.\nПлохой прием сотовой связи.\nСоединение может быть прервано.\nVIN: %1\n\nВаша позиция:\n%2", sk_SK="Spojenie so servisnou centrálou je vytvorené.\nSlabý príjem mobilného telefónu.\nSpojenie sa môže prerušiť.\nVIN: %1\n\nVaša poloha:\n%2", sl_SI="Povezava s servisno centralo je vzpostavljena.\nSlab mobilni sprejem.\nPovezava se morda lahko prekine.\nŠtevilka šasije: %1\n\nVaša lokacija:\n%2", sr_RS="Veza sa servisnom centralom je uspostavljena.\nLoš prijem mobilne mreže.\nEventualno može doći do prekida veze.\nVIN: %1\n\nVaša pozicija:\n%2", sv_SE="Förbindelsen till servicecentralen har upprättats.\nDålig mobilmottagning.\nAnslutningen kan eventuellt brytas.\nChassinummer (VIN): %1\n\nDin position:\n%2", tr_TR="Servis Merkezine bağlantı kuruldu.\nMobil şebeke çekimi kötü.\nBağlantı muhtemelen kesilebilir.\nVIN: %1\n\nKonumun:\n%2", uk_UA="З’єднання з сервісним центром встановлено.\nПоганий прийом мобільного зв'язку.\nЗ'єднання може бути перервано.\nVIN: %1\n\nВаше місцезнаходження:\n%2")
opr__breakdown_connected_screen__text = TextObject(bs_BA="Veza sa servisnom centralom je uspostavljena.\nVIN: %1\n\nVaša pozicija:\n%2", cs_CZ="Spojení se servisní centrálou bylo vytvořeno.\nVIN: %1\n\nVaše poloha:\n%2", da_DK="Der er oprettet forbindelse til servicecentralen:\nStelnummer: %1\n\nDin position:\n%2", de_DE="Die Verbindung zur Servicezentrale ist aufgebaut.\nVIN: %1\n\nDeine Position:\n%2", el_GR="Δημιουργήθηκε η σύνδεση με το κέντρο εξυπηρέτησης.\nVIN: %1\n\nΗ τρέχουσα θέση σας:\n%2", en_GB="Connection to service centre established.\nVIN: %1\n\nYour position:\n%2", es_ES="Conexión con la central de Servicio establecida.\nVIN: %1\n\nSu posición:\n%2", fi_FI="Yhteys palvelukeskukseen on muodostettu.\nVIN: %1\n\nSijaintipaikkasi:\n%2", fr_FR="La connexion au centre d'appels est établie.\nVIN: %1\n\nVotre position:\n%2", hr_HR="Veza sa servisnom centralom je uspostavljena.\nVIN: %1\n\nVaša pozicija:\n%2", hu_HU="Az összeköttetés a szolgáltató központtal létrejött.\nVIN: %1\n\nHelyed:\n%2", it_IT="Stabilito collegamento al centro servizi.\nVIN: %1\n\nPosizione attuale:\n%2", nl_NL="Er wordt verbinding met de Servicecentrale gemaakt.\nVIN: %1\n\nJouw positie:\n%2", no_NO="Det er opprettet forbindelse med kundeservice.\nVIN: %1\n\nDin posisjon:\n%2", pl_PL="Połączenie z centralą serwisową jest nawiązane.\nNumer VIN: %1\n\nTwoja pozycja:\n%2", pt_PT="A ligação ao Callcenter está estabalecida.\nVIN: %1\n\nA tua posição:\n%2", ro_RO="Conexiunea la centrala de service este realizată.\nVIN: %1\n\nPoziţia dumneavoastră:\n%2", ru_RU="Соединение с сервисным колл-центром установлено.\nVIN: %1\n\nВаша позиция:\n%2", sk_SK="Spojenie so servisnou centrálou je vytvorené.\nVIN: %1\n\nTvoja poloha:\n%2", sl_SI="Povezava s servisno centralo je vzpostavljena.\nŠtevilka šasije: %1\n\nVaša lokacija:\n%2", sr_RS="Veza sa servisnom centralom je uspostavljena.\nVIN: %1\n\nVaša pozicija:\n%2", sv_SE="Förbindelsen till servicecentralen har upprättats.\nChassinummer (VIN): %1\n\nDin position:\n%2", tr_TR="Servis Merkezine bağlantı kuruldu.\nVIN: %1\n\nKonumun:\n%2", uk_UA="З’єднання з сервісним центром встановлено.\nVIN: %1\n\nВаше місцезнаходження:\n%2")
