sos__licence_expired_screen__coordinates__text = TextObject(bs_BA="Period važenja licence za hitni poziv je istekao.\nVaša pozicija:\n%1", cs_CZ="Doba platnosti licence pro tísňové volání vypršela.\nVaše poloha:\n%1", da_DK="Licensløbetid for nødopkald udløbet.\nDin position:\n%1", de_DE="Die Lizenzlaufzeit für den Notruf ist abgelaufen.\nDeine Position:\n%1", el_GR="Η διάρκεια ισχύος της άδειας χρήσης της κλήσης ανάγκης έχει λήξει.\nΗ θέση σας:\n%1", en_GB="The emergency call licence period has expired.\nYour location:\n%1", es_ES="La licencia de la llamada de emergencia ha caducado.\nSu posición:\n%1", fi_FI="Hätäpuhelun lisenssin voimassaoloaika on päättynyt.\nSijaintisi:\n%1", fr_FR="Votre licence pour le service d'appel d'urgence a expiré.\nVotre position:\n%1", hr_HR="Vrijeme važenja licence za poziv u nuždi vjerojatno je isteklo.\nVaša pozicija:\n%1", hu_HU="A segélyhívás licencidőtartama lejárt.\nPozíciód:\n%1", it_IT="La durata della licenza per la chiamata d'emergenza è scaduta.\nPosizione attuale:\n%1", nl_NL="De looptijd van de licentie voor de noodoproep is verlopen.\nJouw positie:\n%1", no_NO="Lisensperioden for nødanrop er utløpt.\nDin posisjon:\n%1", pl_PL="Upłynął okres licencji na połączenie alarmowe.\nTwoje położenie:\n%1", pt_PT="O período de validade da licença para a chamada de emergência expirou.\nA tua posição:\n%1", ro_RO="Durata de valabilitate a licenţei pentru apelul de urgenţă a expirat.\nPoziţia dumneavoastră:\n%1", ru_RU="Срок действия лицензии на сервис экстренного вызова истек.\nВаше местоположение:\n%1", sk_SK="Licenčné obdobie pre núdzové volanie uplynulo.\nVaša pozícia:\n%1", sl_SI="Veljavnost licence za klic v sili je potekla.\nVaša lokacija:\n%1", sr_RS="Period važenja licence za poziv u nevolji je istekao.\nVaša pozicija:\n%1", sv_SE="Giltighetstiden för licensen för nödsamtal har löpt ut.\nDin position:\n%1", tr_TR="Acil çağrı için lisans süresi doldu.\nKonumun:\n%1", uk_UA="Строк дії ліцензії на екстрений виклик закінчився.\nВаше місцезнаходження:\n%1")
