sos__licence_expired_screen__no_coordinates__text = TextObject(bs_BA="Licenca za hitni poziv je istekla.", cs_CZ="Platnost licence pro nouzové volání vypršela.", da_DK="Licensløbetid for nødopkald udløbet.", de_DE="Die Lizenzlaufzeit für den Notruf ist abgelaufen.", el_GR="Έληξε η ισχύς της άδειας χρήσης για την κλήση ανάγκης.", en_GB="The licence for the emergency call has expired.", es_ES="La licencia para la llamada de emergencia ha caducado.", fi_FI="Hätäpuhelun lisenssin voimassaoloaika on päättynyt.", fr_FR="La durée de validité de la licence du service d'appel d'urgence a expiré.", hr_HR="Licenca za poziv u nuždi je istekla.", hu_HU="A segélyhívás licence lejárt.", it_IT="La durata della licenza per la chiamata d'emergenza è scaduta.", nl_NL="De looptijd van de licentie voor de noodoproep is verlopen.", no_NO="Lisensen for nødanrop er utløpt.", pl_PL="Licencja na połączenie alarmowe straciła ważność.", pt_PT="A licença para a chamada de emergência expirou.", ro_RO="Perioada de licenţă pentru apelul de urgenţă a expirat.", ru_RU="Срок действия лицензии на экстренные вызовы истек.", sk_SK="Platnosť licencie pre núdzové volanie uplynula.", sl_SI="Veljavnost licence za klic v sili je potekla.", sr_RS="Licenca za poziv u nevolji je istekla.", sv_SE="Giltighetstiden för licensen för nödsamtal har löpt ut.", tr_TR="Acil çağrı için lisans süresi doldu.", uk_UA="Строк дії ліцензії для екстреного виклику завершився.")
sos__licence_expired_screen__no_permission__text = TextObject(bs_BA="Period važenja licence za hitni poziv je istekao. Deaktivirali ste usluge utemeljene na lokaciji. Iz\ntog razloga se Vaša pozicija ne može prikazati.", cs_CZ="Doba platnosti licence pro tísňové volání vypršela. Deaktivovali jste služby založené na poloze.\nProto nelze zobrazit vaši polohu.", da_DK="Licensløbetid for nødopkald udløbet. Du har deaktiveret stedrelaterede tjenester. Derfor kan\ndin position ikke vises.", de_DE="Die Lizenzlaufzeit für den Notruf ist abgelaufen. Du hast ortsbasierte Dienste deaktiviert.\nDaher kann deine Position nicht angezeigt werden.", el_GR="Η διάρκεια ισχύος της άδειας χρήσης της κλήσης ανάγκης έχει λήξει. Έχετε απενεργοποιήσει τις\nυπηρεσίες που βασίζονται στην τοποθεσία. Γι’ αυτό δεν είναι εφικτή η ένδειξη της θέσης σας.", en_GB="Emergency call licence period has expired. You have deactivated location-based services. Your\nposition therefore cannot be displayed.", es_ES="La licencia de la llamada de emergencia ha caducado. Los servicios de localización están\ndesactivados. Por consiguiente, no se puede mostrar la posición del vehículo.", fi_FI="Hätäpuhelun lisenssin voimassaoloaika on päättynyt. Paikkaperusteiset palvelut on\ndeaktivoitu. Sijaintiasi ei sen vuoksi voida näyttää.", fr_FR="Votre licence pour le service d'appel d'urgence a expiré. Vous avez désactivé des services\ngéolocalisés. Par conséquent, votre position ne peut pas être affichée.", hr_HR="Vrijeme važenja licence za poziv u nuždi je isteklo. Deaktivirali ste usluge bazirane na lokaciji.\nStoga nije moguće prikazati vašu poziciju.", hu_HU="A segélyhívás licencidőtartama lejárt. Deaktiváltad a helyalapú szolgáltatásokat. Ezért nem\njeleníthető meg a pozíciód.", it_IT="La durata della licenza per la chiamata d'emergenza è scaduta. L'utente ha disattivato i servizi\nbasati sulla posizione, pertanto non è possibile visualizzare la posizione.", nl_NL="De looptijd van de licentie voor de noodoproep is verlopen. Je hebt locatiegebaseerde diensten\ngedeactiveerd. Daarom kan je positie niet worden weergegeven.", no_NO="Lisensperioden for nødanrop er utløpt. Du har deaktivert stedsbaserte tjenester. Derfor kan\nikke posisjonen din vises.", pl_PL="Upłynął okres licencji na połączenie alarmowe. Użytkownik wyłączył usługi oparte na\nlokalizacji. Dlatego nie jest możliwe wyświetlenie Twojego położenia.", pt_PT="O período de validade da licença para a chamada de emergência expirou. Desativas-te os dados\nbaseados na localização. Por isso, não é possível apresentar a tua posição.", ro_RO="Durata de valabilitate a licenţei pentru apelul de urgenţă a expirat. Aţi dezactivat servicii\nbazate pe localizare. Din acest motiv nu poate fi afişată poziţia dumneavoastră.", ru_RU="Срок действия лицензии на сервис экстренного вызова истек. Вы отключили сервисы с\nопределением местоположения. Поэтому ваше местоположение не может быть\nотображено.", sk_SK="Licenčné obdobie pre núdzové volanie uplynulo. Deaktivovali ste služby založené na polohe.\nPreto nie je možné zobraziť vašu polohu.", sl_SI="Veljavnost licence za klic v sili je potekla. Deaktivirali ste storitve glede na lokacijo, zato vaše\nlokacije ni mogoče prikazati.", sr_RS="Period važenja licence za poziv u nevolji je istekao. Deaktivirali ste usluge zasnovane na lokaciji.\nIz tog razloga vaša pozicija neće moći da se prikaže.", sv_SE="Giltighetstiden för licensen för nödsamtal har löpt ut. Du har avaktiverat platsberoende\ntjänster. Därför kan din position inte visas.", tr_TR="Acil çağrı için lisans süresi doldu. Konum tabanlı hizmetleri devre dışı bıraktın. Bu nedenle\nkonumun görüntülenemiyor.", uk_UA="Строк дії ліцензії на екстрений виклик закінчився. Ви вимкнули служби з визначенням\nмісцезнаходження. Тому ваше місцезнаходження не може бути відображено.")
sos__licence_expired_screen__title = TextObject(bs_BA="Greška licence", cs_CZ="Chyba licence", da_DK="Licensfejl", de_DE="Lizenzfehler", el_GR="Σφάλμα άδειας", en_GB="Licence error", es_ES="Error de licencia", fi_FI="Lisenssivirhe", fr_FR="Erreur de licence", hr_HR="Greška u licenci", hu_HU="Licenchiba", it_IT="Errore licenza", nl_NL="Licentiefout", no_NO="Lisensfeil", pl_PL="Błąd licencji", pt_PT="Erro na licença", ro_RO="Eroare de licenţă", ru_RU="Ошибка лицензии", sk_SK="Chyba licencie", sl_SI="Napaka licence", sr_RS="Greška u licenci", sv_SE="Licensfel", tr_TR="Lisans hatası", uk_UA="Помилка ліцензії")
